/**
 * verifier.worker.ts — Web Worker entry point for the heavy backtracking
 * solver. Keeps the main thread free during BuilderSheet's "Validate" step.
 *
 * Protocol (postMessage in both directions):
 *   in:  { id, kind: 'verifyUnique',          clues, w, h }
 *   in:  { id, kind: 'verifyUniqueDeductive', solution, w, h }
 *   out: { id, ok: true,  result: boolean }
 *   out: { id, ok: false, error: string }
 *
 * Time: bounded by the existing solver caps. Space: O(N) for the solver.
 */
import { verifyUnique, verifyUniqueDeductive } from './verifier';
import type { Clues } from './types';

type Req =
  | { id: number; kind: 'verifyUnique'; clues: Clues; w: number; h: number }
  | { id: number; kind: 'verifyUniqueDeductive'; solution: (0 | 1)[]; w: number; h: number };

self.addEventListener('message', (e: MessageEvent<Req>) => {
  const msg = e.data;
  try {
    let result: boolean;
    if (msg.kind === 'verifyUnique') {
      result = verifyUnique(msg.clues, msg.w, msg.h);
    } else {
      result = verifyUniqueDeductive(msg.solution, msg.w, msg.h);
    }
    (self as unknown as Worker).postMessage({ id: msg.id, ok: true, result });
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    (self as unknown as Worker).postMessage({ id: msg.id, ok: false, error: message });
  }
});
