import type { Board, Coord, Mark, CellMarkInput, EtchSize } from './types';
import { computeClues } from './clues';
import { SIZE_DIMS } from './types';

export function freezeBoard(b: Board): Board {
  Object.freeze(b);
  Object.freeze(b.cells);
  Object.freeze(b.solution);
  Object.freeze(b.clues.rows);
  Object.freeze(b.clues.cols);
  b.clues.rows.forEach(r => Object.freeze(r));
  b.clues.cols.forEach(c => Object.freeze(c));
  return b;
}

export function makeBoard(solution: ReadonlyArray<0 | 1>, w: number, h: number): Board {
  if (solution.length !== w * h) throw new Error(`solution length ${solution.length} !== ${w * h}`);
  const clues = computeClues(solution, w, h);
  const cells: Mark[] = new Array(w * h).fill('unmarked');
  return freezeBoard({ rows: h, cols: w, clues, cells, solution });
}

export function emptyBoardOfSize(size: EtchSize): Board {
  const { w, h } = SIZE_DIMS[size];
  const solution = new Array(w * h).fill(0) as (0|1)[];
  return makeBoard(solution, w, h);
}

export function mark(b: Board, c: Coord, kind: CellMarkInput): Board {
  const idx = c.row * b.cols + c.col;
  if (idx < 0 || idx >= b.cells.length) return b;
  const cur = b.cells[idx];
  let next: Mark;
  if (kind === 'clear') next = 'unmarked';
  else if (kind === 'fill') next = cur === 'fill' ? 'unmarked' : 'fill';
  else /* cross */         next = cur === 'cross' ? 'unmarked' : 'cross';
  if (next === cur) return b;
  const cells = b.cells.slice() as Mark[];
  cells[idx] = next;
  return freezeBoard({ ...b, cells });
}
