import { solveLine } from './line-solver';
import type { Board, Mark, TechniqueLevel, SolveResult } from './types';
import { freezeBoard } from './board';

export function solveBoard(b: Board): SolveResult {
  let cells = b.cells.slice() as Mark[];
  let lastTech: TechniqueLevel = 'none';
  let iterations = 0;
  // True multi-line: a row pass makes new discoveries AFTER columns have already contributed.
  // This is the row→col→row feedback chain (B&K "column-then-row interplay").
  let rowProgressAfterColFeedback = false;
  let colHasEverContributed = false;

  while (true) {
    iterations++;
    let progress = false;
    let rowProgressThisIter = false;

    // Rows
    for (let r = 0; r < b.rows; r++) {
      const line = cells.slice(r * b.cols, r * b.cols + b.cols);
      const forced = solveLine(b.clues.rows[r]!, line);
      const tech = classifyLineForce(b.clues.rows[r]!, line, forced);
      for (let i = 0; i < b.cols; i++) {
        if (forced[i] !== 'unmarked' && cells[r * b.cols + i] === 'unmarked') {
          cells[r * b.cols + i] = forced[i]!;
          progress = true;
          rowProgressThisIter = true;
          if (techRank(tech) > techRank(lastTech)) lastTech = tech;
        }
      }
    }

    // Row progress in iteration 2+ (after columns have fed back) → multi-line
    if (rowProgressThisIter && colHasEverContributed) rowProgressAfterColFeedback = true;

    // Columns
    for (let c = 0; c < b.cols; c++) {
      const line: Mark[] = [];
      for (let r = 0; r < b.rows; r++) line.push(cells[r * b.cols + c]!);
      const forced = solveLine(b.clues.cols[c]!, line);
      const tech = classifyLineForce(b.clues.cols[c]!, line, forced);
      for (let r = 0; r < b.rows; r++) {
        if (forced[r] !== 'unmarked' && cells[r * b.cols + c] === 'unmarked') {
          cells[r * b.cols + c] = forced[r]!;
          progress = true;
          colHasEverContributed = true;
          if (techRank(tech) > techRank(lastTech)) lastTech = tech;
        }
      }
    }

    if (!progress) break;
    if (iterations > b.rows * b.cols) break; // safety cap
  }

  // Check solved: every '1' in solution is 'fill' in cells.
  let solved = true;
  for (let i = 0; i < b.solution.length; i++) {
    if (b.solution[i] === 1 && cells[i] !== 'fill') { solved = false; break; }
  }

  // Promote to multi-line only when genuine row→col→row feedback was required
  if (solved && rowProgressAfterColFeedback && techRank(lastTech) < techRank('multi-line')) {
    lastTech = 'multi-line';
  }

  const board = freezeBoard({ ...b, cells: Object.freeze(cells) as ReadonlyArray<Mark> });
  return { solved, board, lastTechnique: lastTech, iterations };
}

function classifyLineForce(clues: number[], line: ReadonlyArray<Mark>, forced: ReadonlyArray<Mark>): TechniqueLevel {
  if (clues.length === 1 && clues[0] === 0) return 'completed-clue';
  // If existing fills already satisfy the clue, remaining deductions are trivial (completed-clue).
  if (fillRunsMatch(line, clues)) return 'completed-clue';
  const totalLen = clues.reduce((s, c) => s + c, 0) + (clues.length - 1);
  if (totalLen === line.length) return 'completed-clue';
  for (const c of clues) if (c * 2 > line.length) return 'overlap';
  const N = line.length;
  for (let i = 0; i < N; i++) {
    if (forced[i] === 'fill' && (i === 0 || i === N - 1)) return 'forced-edge';
  }
  if (forced.some(f => f !== 'unmarked')) return 'completed-clue-elim';
  return 'none';
}

function fillRunsMatch(line: ReadonlyArray<Mark>, clues: number[]): boolean {
  const runs: number[] = [];
  let cur = 0;
  for (const v of line) {
    if (v === 'fill') cur++;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  if (cur > 0) runs.push(cur);
  if (runs.length !== clues.length) return false;
  for (let i = 0; i < runs.length; i++) if (runs[i] !== clues[i]) return false;
  return true;
}

const TECH_ORDER: TechniqueLevel[] = ['none', 'completed-clue', 'forced-edge', 'overlap', 'completed-clue-elim', 'multi-line'];
export function techRank(t: TechniqueLevel): number { return TECH_ORDER.indexOf(t); }
